function _initPage() {
    var records = arguments.length > 0 && arguments[0] !== undefined ? arguments[0] : 0;

    var _this16 = this;

    var currentPage = arguments.length > 1 && arguments[1] !== undefined ? arguments[1] : 0;
    var rowNum = arguments.length > 2 && arguments[2] !== undefined ? arguments[2] : 0;


    var self = this;

    // 전체 페이지 사이즈
    var totalPageSize = Math.ceil(records / rowNum); // 총 페이지

    // 페이지 그룹 사이즈
    var pageGroupSize = this.pageGroupSize;

    // 전체 페이지 그룹
    var totalPageGroupSize = Math.ceil(totalPageSize / pageGroupSize);
    // 총 페이지 / 페이지 목록 갯수 --> 뿌려줄 데이터 

    // 현재 페이지 그룹
    var currentPageGroup = Math.ceil(currentPage / pageGroupSize);
    // 현재 페이지가 총 페이지 리스트 중 몇번째 인지

    // 페이지 리스트가 1보다 작으면 1로 초기화

    // 페이지 리스트가 총 페이지 리스트보다 커지면 총 페이지 리스트로 설정

    if (currentPage < 1) currentPage = 1;
    if (currentPageGroup > totalPageGroupSize) currentPageGroup = totalPageGroupSize;

    // 시작 페이지

    // 끝 페이지

    var startPageGroup = (currentPageGroup - 1) * pageGroupSize + 1;
    var endPageGroup = startPageGroup + pageGroupSize - 1;

    // 시작 페이지와 끝페이지가 1보다 작으면 1로 설정

    // 끝 페이지가 마지막 페이지보다 클 경우 마지막 페이지값으로 설정

    if (startPageGroup < 1) startPageGroup = 1;

    if (endPageGroup > totalPageSize) endPageGroup = totalPageSize;
    if (endPageGroup < 1) endPageGroup = 1;

    // 현재 페이지 컨테이너 초기화
    this.$pageContainer.html('');

    var className = BxGrid.className;

    var $pagingContainer = $('<div class="bx-ui-' + className + ' bw-paging add-mg-t"></div>');

    if (currentPageGroup > 1) {

        var $prevBtnGroup = $('<div class="ctr-btn"></div>');

        var $first = _createPagingNavElement('forward', function (e) {
            return _this16.goPage(1);
        });
        var $prev = _createPagingNavElement('pre', function (e) {
            return _this16.goPage(startPageGroup - 1);
        });

        $prevBtnGroup.append($first);
        $prevBtnGroup.append($prev);

        $pagingContainer.append($prevBtnGroup);
    }

    var $pagingGroup = $('<div class="paging-btn"></div>');

    var _loop = function _loop(i) {

        var $a = null;

        if (i === Number(currentPage)) {
            $a = $('<button type="button" class="btn-paging on" title =' + i + '>' + i + '</button>');
        } else {
            $a = $('<button type="button" class="btn-paging" title =' + i + '>' + i + '</button>');
            $a.on('click', function (e) {
                return _this16.goPage(i);
            });
        }

        $pagingGroup.append($a);
    };

    for (var i = startPageGroup; i <= endPageGroup; i++) {
        _loop(i);
    }

    $pagingContainer.append($pagingGroup);

    if (currentPageGroup < totalPageGroupSize) {

        var $nextCtrBtn = $('<div class="ctr-btn"></div>');

        var $next = _createPagingNavElement('next', function (e) {
            return _this16.goPage(endPageGroup + 1);
        });
        var $last = _createPagingNavElement('backward', function (e) {
            return _this16.goPage(totalPageSize);
        });

        $nextCtrBtn.append($next);
        $nextCtrBtn.append($last);

        $pagingContainer.append($nextCtrBtn);
    }

    this.$pageContainer.append($pagingContainer);
}

